sp_widget.client_script:
api.controller = function($scope, spUtil, $location, $window, mandatoryValidator,$rootScope) {
    var c = this;

    c.save = function() {

			var result= mandatoryValidator.validate(c.data.f);

			if(!result.valid)
				{
					spUtil.addErrorMessage(result.message);
					return;
				}

        c.data.action = "save";        
        c.data.form = c.data.f;
        c.server.update().then(function(response) {

						var newSysId = response.sys_id;
						var actionPerformed= response.actionPerformed;
						var recName= response.recName;
						//alert(newSysId);

					if(newSysId!=null && newSysId!=-1)
					spUtil.addInfoMessage(recName+" "+actionPerformed+" sucessfully");


					setTimeout(function() {

						if(c.data.table=="x_ctans_incentnow_plan")
						{		
							if( newSysId!=-1 && newSysId!=null)
							{
								var url = "?id=create_plan&"+"table="+c.data.table+"&sys_id=" + newSysId+"&step=earning";
								$location.url(url);
							}
							//$rootScope.$broadcast('planupdation');
						}
						else
							{
								var url  = "?id=incentnow_form&"+"table="+c.data.table+"&sys_id=" + newSysId;
								$location.url(url);
							}

					}, 2000); 







        });

    };

	c.generateFiscal = function()
	{
		 c.data.action = "generateFiscal";
    	c.server.update().then(function(response){
      //spUtil.addInfoMessage("Display Names Saved");
				var newSysId = response.sys_id;
					var url = "?id=incentnow_form&sys_id=" + response.sys_id;
				$location.url(url);
    });
	}

	c.goBack=function () {

  const prev = sessionStorage.getItem('prevPage');
		//alert(prev);

  if (prev) {
    $location.url(prev);
  } else {
    // fallback if nothing stored
    window.history.back();
  }
}
};

sp_widget.css:
.footer-actions {
  display: flex;
  justify-content: flex-end;
  gap: 12px;
}

.fiscal-pill {
  background-color: #050521; /* same dark color */
  color: #fff;
  border: none;
  border-radius: 5px; /* makes it fully rounded */
  padding: 8px 18px;
  font-size: 14px;
  transition: all 0.2s ease;
}

.fiscal-pill:hover {
  background-color: #0a0a3a;
}

/*.back-btn {
  background: #f5f5f5;
  border: none;
  padding: 8px 14px;
  border-radius: 20px;
  cursor: pointer;
  font-size: 14px;
} */

.back-btn:hover {
  background: #e0e0e0;
}

.panel-heading {
  display: flex;
  align-items: center;   /* vertically center */
  gap: 10px;             /* space between button & text */
}

.back-btn {
  border: none;
  background: transparent;
  font-size: 18px;
  cursor: pointer;
}

.panel-heading h4 {
  margin: 0;  /* removes default spacing issue */
}


/* MAIN CARD */
.modern-card {
  border-radius: 14px;
  border: 1px solid #e5e7eb;
  box-shadow: 0 4px 4px rgba(0,0,0,0.06);
  overflow: hidden;
  transition: all 0.25s ease;
}

/* hover effect */
.modern-card:hover {
  box-shadow: 0 8px 24px rgba(0,0,0,0.08);
}

/* HEADER */
.modern-header {
  display: flex;
  align-items: center;
  gap: 10px;
  background: linear-gradient(to right, #f9fafb, #f3f4f6);
  border-bottom: 1px solid #e5e7eb;
  padding: 14px 18px;
}

/* TITLE */
.modern-title {
  margin: 0;
  font-size: 18px;
  font-weight: 600;
}

/* BACK BUTTON */
.back-btn {
  background: #f3f4f6;
  border: none;
  border-radius: 8px;
  padding: 6px;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: all 0.2s ease;
}

.back-btn img {
  width: 20px;
  height: 20px;
}

.back-btn:hover {
  background: #e5e7eb;
}

/* BODY */
.modern-body {
  padding: 20px;
  background: #ffffff;
}

/* FOOTER */
.modern-footer {
  display: flex;
  justify-content: flex-end;
  //background: #fafafa;
  border-top: 1px solid #e5e7eb;
  padding: 12px 18px;
}

/* BUTTON */
.modern-btn {
  border-radius: 8px;
  padding: 8px 18px;
  font-weight: 500;
  transition: all 0.2s ease;
  background: #000000;
}

.modern-btn:hover {
  transform: translateY(-1px);
  box-shadow: 0 3px 10px rgba(0,0,0,0.1);
}

sp_widget.script:
(function() {

		//data.table=$sp.getParameter('table') || "x_ctans_incentnow_plan";
		data.table  = (input && input.table)  || options.table  || $sp.getParameter('table')  || "";
		data.sys_id = (input && input.sys_id) || options.sys_id || $sp.getParameter('sys_id') || "-1";
		data.view   = (input && input.view)   || options.view   || $sp.getParameter('view')   || "portal_view";
   		data.f=$sp.getForm(data.table,data.sys_id,'',data.view);
		data.f=new x_ctans_incentnow.IncentNowPortalUtils().applyPlaceholders(data.f);
		if(data.table)
			{
				var tablelabel= new GlideRecordSecure(data.table);
						data.table_label=tablelabel.getLabel();
			}


		data.fetchButtonName="Save";
		if(data.table=="x_ctans_incentnow_fiscal_calendar" && data.sys_id=="-1")
			{
				data.fetchButtonName="Create Fiscal Calendar & Generate Periods"
			}	
		if(data.table=="x_ctans_incentnow_plan")
			{
				data.fetchButtonName="Save Plan";
			}

	if (input && input.action == "save") {

    var table = data.table;
    var sysId = data.sys_id;

		//gs.info("Console log "+data.table+ " -- "+data.sys_id);

    if (!input.form || !input.form._fields) {
        gs.addErrorMessage("Form data missing");
        return;
    }

    var fields = input.form._fields;

    var recordGR = new GlideRecordSecure(table);

    //  Creation
    if (sysId == "-1") {

        recordGR.initialize();

        for (var key in fields) {
            if (fields[key].value !== undefined) {
                recordGR.setValue(key, fields[key].value);
            }
        }

        var newSysId = recordGR.insert();

				if(newSysId)
					{
						 	//gs.addInfoMessage(gr.getDisplayValue()+" created successfully ");
							data.sys_id = newSysId;
							data.recName= recordGR.getDisplayValue();
							data.actionPerformed='created';

					}


			if(data.table=="x_ctans_incentnow_fiscal_calendar" && newSysId)
				{
					try {
							 var gen = new x_ctans_incentnow.IncentNowFiscalPeriodGenerator();
									gen.generatePeriods(newSysId);
									gs.addInfoMessage('Fiscal periods generated for '+ recordGR.getDisplayValue()+' successfully.');
							} catch (e) {
									gs.addErrorMessage('Error generating fiscal periods: ' + e.message);
							}	
				}


    } 
    // Updation
    else {

        if (!recordGR.get(sysId)) {
            gs.addErrorMessage("Record not found");
            return;
        }

        for (var key in fields) {
            if (fields[key].value !== undefined) {
                recordGR.setValue(key, fields[key].value);
            }
        }


        data.sys_id=recordGR.update();


			if(data.sys_id)
					{

							data.recName= recordGR.getDisplayValue();
							data.actionPerformed='updated';
					}

        //gs.addInfoMessage("Record updated successfully");
    }
}

	if(input)
		{
			if(input.action=="generateFiscal")
					{
						//gs.addErrorMessage("Generate Fiscal Running");
						try {
						 var gen = new x_ctans_incentnow.IncentNowFiscalPeriodGenerator();
								gen.generatePeriods(data.sys_id);

								gs.addInfoMessage('Fiscal periods generated successfully.');
						} catch (e) {
								gs.addErrorMessage('Error generating fiscal periods: ' + e.message);
						}

					}
		}



})();
